command.text:
        /* <flatten type="Javascript"> */
var f = this, g = f.getItem('dmquyenct')._controlBehavior, l0 = g._getColumnOrder('kieu_duyet'), l1 = g._getColumnOrder('status'), v0, v1, c0, c1;
for (var i = 0; i < g._rowCount - 1; i++) {
  v0 = $func.trim(g._getItemValue(i + 1, l0));
  v1 = $func.trim(g._getItemValue(i + 1, l1));
  for (var j = i + 1; j < g._rowCount; j++) {
    c0 = $func.trim(g._getItemValue(j + 1, l0));
    c1 = $func.trim(g._getItemValue(j + 1, l1));
    if (c0 == v0 && c1 == v1) {
      f._checked = false;
      g._errorObject = g._getItem(j + 1, l0);
      var e = (f._language == 'v' ? 'Trường <span class="Highlight">Kiểu duyệt</span> và <span class="Highlight">Từ trạng thái</span> có giá trị nhập không hợp lệ, giá trị này đã được khai báo.' : 'Field <span class="Highlight">Category</span> and <span class="Highlight">From Status</span> has invalid value, its value already exists.');
      $message.show(e, String.format('$find(\'{0}\')._errorObject.focus()', g.get_id()));
      break;
    }
  }
  if (!f._checked) break;
}
/* </flatten> */

script.text:
      /* <flatten type="Javascript"> */
function active$FormApprovalRoles(f) {
  f.add_onResponseComplete(on$FormApprovalRoles$ResponseComplete);
  f.add_commandEvent(on$FormApprovalRoles$ExecuteCommand);
  setDefaultValue$FormApprovalRoles(f);
}
function scatter$FormApprovalRoles(f) {setDefaultValue$FormApprovalRoles(f);}
function close$FormApprovalRoles(f) {try {f.remove_onResponseComplete(on$FormApprovalRoles$ResponseComplete)} catch (ex) {}}
function on$FormApprovalRoles$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      objectBehavior$Dir$Irregular.checkCode(f, 'ma_quyen');
      break;
    default:
      break;
  }
}
function on$FormApprovalRoles$ExecuteCommand(sender, e) {
  var action = e.type.Action, f = sender, g = f.getItem('dmquyenct')._controlBehavior;
  switch (action) {
    case 'Gather':
      g.setSequenceNumber('line_nbr');
      break;
    default:
      break;
  }
}
function setDefaultValue$FormApprovalRoles(f) {if (f._action == 'New') f.setItemValue('loai_duyet', f.grid._approvalType);}
/* </flatten> */
      &ScriptIrregular;
